//   2. maxTokens fix for tool-using DMs (600 -> 1500) so strategist
//      replies don't get truncated mid-sentence
//   3. Per-tool audit row writes with cache_hit metadata
//   4. Dashboard quota counter (live + cached Tavily today)
//   5. Dashboard in-flight indicator ("X is thinking..." while responder works)
//
// PREREQUISITE - run this SQL in Supabase BEFORE running the scaffold:
//
//   create table if not exists tool_result_cache (
//     id uuid primary key default gen_random_uuid(),
//     tenant_id uuid not null,
//     tool_name text not null,
//     cache_key text not null,
//     result_content text not null,
//     expires_at timestamptz not null,
//     created_at timestamptz not null default now()
//   );
//
//   create unique index if not exists tool_result_cache_lookup_idx
//     on tool_result_cache (tenant_id, tool_name, cache_key);
//
//   create index if not exists tool_result_cache_expiry_idx
//     on tool_result_cache (expires_at);
//
//   alter table dms add column if not exists in_flight_since timestamptz;

import { mkdirSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';

const ROOT = process.cwd();

function writeFile(relPath, base64Content) {
  const full = resolve(ROOT, relPath);
  mkdirSync(dirname(full), { recursive: true });
  writeFileSync(full, Buffer.from(base64Content, 'base64'));
  console.log('  + ' + relPath);
}

console.log('');
console.log('Day 5.3 scaffold - Tool use polish (cache + maxTokens + dashboard)');
console.log('Writing 8 files to: ' + ROOT);
console.log('');

writeFile('apps/dashboard/app/api/tools/quota/route.ts', '');
writeFile('apps/dashboard/app/page.tsx', '');
writeFile('apps/orchestrator/src/agents/runner.ts', '');
writeFile('apps/orchestrator/src/rituals/dm-responder.ts', '');
writeFile('apps/orchestrator/src/tools/cache.ts', '');
writeFile('apps/orchestrator/src/tools/types.ts', '');
writeFile('apps/orchestrator/src/tools/web-search.ts', '');
writeFile('apps/orchestrator/supabase/migrations/0008_day5_3.sql', '');

